import{s as e}from "./_plugin-vue_export-helper-suvPoTZX.js";import{i as t,r as n}from "./index-BtJPp6wo.js";var r={"welcome-text":`You have entered a portal where two mystical forces converge – Tarot and Runes. Each holds its own secrets, offering guidance to life's deepest questions. Choose your path: the enigmatic Tarot cards or the ancient symbols of the Runes. Immerse yourself in the magic of divination and let artificial intelligence be your guide through the mysteries of the unknown!`,"welcome-advice-fallback":`The stars are whispering, and your path unfolds step by step.`,"welcome-advice-label":`Whisper of Fate for Today`,"welcome-subtitle":`A Mystical Welcome to the AI Digital Oracle`,"welcome-title-start":`The oracle of`,"welcome-title-end":`awaits`,"tarot-label":`TAROT`,"runes-label":`RUNES`,"What speaks to your soul?":`What speaks to your soul?`,"welcome-title":`A Mystical Welcome to the AI Digital Oracle!`,"what speak":`What speaks to your soul?`,"two-paths":`Two paths lie before you, like a crossroads of destiny. The choice is yours: will you trust the storytellers or heed the wisdom of ancient symbols? Or perhaps, you’ll dare to explore both paths?`,"tarot-text":`Tarot cards are the language of ancient archetypes, weaving a web that connects the past, present, and future. Step into a realm where each card is a chapter of your story, waiting to be revealed.
Through symbols, figures, and hidden meanings, the Tarot reflects the forces shaping your life and the choices that lie before you. Every spread is a mirror of your journey, offering insight, guidance, and a glimpse into the unseen threads of fate.
Draw the cards and discover what the story of the moment has to reveal.`,"tarot-welcome-text":`Ancient Tarot cards carry the wisdom of centuries. They reveal hidden currents of fate and help uncover answers.`,"rune-welcome-text":`Runic symbols carry ancient wisdom. Their message shifts like the winds of fate, guided by the question that lingers in your thoughts.`,"chosen-rune":`Touch destiny - choose rune`,"random-rune":`Let fate choose for you`,"Random rune":`Random rune`,"shuffle-runes":`Shuffle runes`,"Get prediction":`Get prediction`,"Rune-welcome":`Bound by fate, marked by runes`,"runes-no-selection":`Select a rune to hear its whisper.`,"Make your choice":`Choose the path that awaits:`,"Daily Tarot":`Daily Tarot`,"3 Cards Tarot":`3 Cards Tarot`,"Personal reading":`Personal reading`,"tarot-pos-past":`Woven`,"tarot-pos-present":`Held`,"tarot-pos-future":`Written`,Love:`Love`,Relationship:`Relationship`,Money:`Money`,Business:`Business`,Telling:`Telling`,Close:`Close`,"Your telling:":`Your telling:`,"tarot-error":`The oracle is silent for now. Try again in a moment.`,"rune-error":`The runes are silent for now. Try again in a moment.`,"Tarot Experiences Await":`Tarot Experiences Await`,"How to":`How to`,"Explore Tarot":`Learn interpreting one or three-card spreads, and unlock the secrets of effective Tarot readings.`,"Explore More":`Explore More`,"daily subscribe":`Subscribe`,"daily subscribe button":`What does the day hold for you? A daily Tarot reading straight to your email.`,"TG bot":`TG Bot`,"TG text button":`Experience the magic of Tarot readings on our Telegram bot!`,"How to use:":`How to use:`,"Guidance:":`Guidance`,"slide.kicker":`Reading Type`,"slide1.title":`Card of the Day`,"slide1.text":`
Focus on the question within you.<br>
Let the silence speak.<br>
Touch the card — and it will reveal itself.<br>
Receive its message… and watch how it unfolds.
`,"slide2.title":`Three Cards`,"slide2.text":`
Ask the question that lingers within.<br>
Choose three cards.<br><br>

<strong>First</strong> — what has already been woven into your path.<br>
<strong>Second</strong> — what is unfolding now.<br>
<strong>Third</strong> — what is drawing closer to you.
`,"slide3.title":`Personal Reading`,"slide3.text":`
Choose the word that calls to you.<br>
Stay with the feeling.<br>
Allow the message to come.<br>
Truth will answer where you feel it most.
`,"slide1.name":`Guidance`,"reflect.title":`Reflection`,"reflect.text":`Reflect on the information gained from the cards' meanings. Consider how you can apply these insights to make informed decisions or take suitable actions in the areas of life the cards have highlighted. Remember tarot reading is a tool for self-analysis and personal understanding. Trust your intuition and use the cards as a source of guidance rather than a definitive glimpse of the future.`,"subscription-text":`<h2>The universe is ready to unveil its secrets.</h2><p>Subscribe and receive daily Tarot prophecies straight to your email.</p>`,"Manage subscription":`Manage subscription`,"Subscribe for Daily Tarot":`Subscribe for Daily Tarot`,"TG text":`<h1>Join us on Telegram</h1><p>Open the door to the world of mystery and magic of the tarot! Receive unique fortune-telling, explore the Arcana, and enjoy a magical journey into the world of ancient wisdom and inspiration.</p>`,"daily-next":`Daily card returns at {time}`,"Stay Connected":`The Magic at Your Fingertips!`,"Stay connected text":`<p>Visit our <a href="https://www.buymeacoffee.com/mnimi" target="_blank">Buy Me a Coffee</a> and add a drop of magic to our cauldron of divination. Your support helps the energy of divination flow freely and lets the mysticism flourish!</p><p>Be part of the enchantment, and the magic will find its way back to you!</p>`,"rune-text":`Runes are the voice of the northern winds and the ancient earth. They speak not in words but in timeless symbols, guiding you to truth through the whispers of the ages.
Each rune carries the echo of forgotten wisdom — a sign carved from myth, fate, and the deep currents of destiny. When the runes are cast, they reveal patterns hidden beneath the surface of your question, illuminating paths you may not yet see.
Listen carefully, for in their silent language the old powers still speak.`,"soul-prev":`Return to the Past Sign`,"soul-next":`Follow the Next Omen`,"soul-open-tarot":`Draw the cards`,"soul-open-runes":`Cast the runes`,"soul-inscription-tarot":`✦ ARCANA · DIVINATION · FATE ✦`,"soul-inscription-runes":`✦ FUTHARK · NORSE WISDOM · ANCIENT EARTH ✦`,faq:`FAQ (Secrets You Seek to Uncover)`,"How do predictions work?":``,"how do predictions work-text":`When you make a choice, it’s as if you turn the page of your destiny. Our AI merely helps you read what is already written in the delicate threads of time.`,"Tarot or Runes: which is more accurate?":``,"Tarot or Runes: which is more accurate-text":`Tarot is a mirror of the soul, revealing what lies within, unlocking the hidden depths of your emotions and desires. Runes, on the other hand, are a compass, guiding you toward your path, offering clarity when you feel lost and lighting the way through uncertainty. Each tool holds its truth in the right hands—or in the hands of our AI.`,"How can I begin a reading?":``,"How can I begin a reading-text":`Simply click on the image, and the ancient forces will awaken. No need for rituals or crystal balls—everything is already prepared for you!`,"Can I do multiple readings?":``,"Can I do multiple readings-text":`Of course! Each reading is like a new chapter in your story. The more you ask, the more pages of your destiny unfold.`,"What if I don't know what to ask?":``,"What if I don't know what to ask-text":`Don’t worry—fate knows what you need. Ask any question, even the simplest one, and you’ll receive the answer you’ve been seeking for so long.`,"Is it free?":``,"Is it free-text":`Yes, ancient magic harnessed by modern technology on our site is free for all seekers. For those who wish to delve deeper, we offer additional services, such as a subscription with daily predictions or access to our mystical Telegram channel, for a symbolic fee. Your support fuels the enchantment and helps us weave even greater wonders!`,"How accurate are the predictions?":``,"How accurate are the predictions-text":`The wisdom of the ancients + the power of artificial intelligence = a perfect hit. Though sometimes, fate enjoys playing with riddles.`,"What if I don't like the answer?":``,"What if I don't like the answer-text":`Fate occasionally speaks a bitter truth. But remember: answers are merely a guide, and the final decision rests with you.`,"About this project":``,"About this project-text":`<p>Welcome to a portal where ancient symbols meet modern technology.</p><p>Here, the timeless languages of Tarot and Runes are explored through artificial intelligence — creating a digital oracle that bridges ancient traditions and modern code.</p><p>This project is part of my academic journey into the world of software development.</p><p>Think of it as a sandbox for experimentation, where I explore ideas, technologies, and creative ways to combine storytelling, symbolism, and AI.</p><p>Every line of code here is both practice and curiosity — an attempt to see how technology can give new form to old mystical systems.</p><p>If you're exploring this page as part of my portfolio, welcome.</p><p>And if you're here simply out of curiosity — <a class="rich-link" href="/tarot">let the cards speak</a> and <a class="rich-link" href="/runes">let the runes whisper</a>.</p><p>✨ May the symbols speak to you. ✨</p>`,"Paths and Laws of Fate":``,"Paths and Laws of Fate-text-1":`The Tarot and Rune readings, elevated by this mystical tool, are intended solely for immersion in the world of magic and entertainment. They should not be taken as professional prophecies or predictions of inevitable events.`,"Paths and Laws of Fate-text-2":`<p>All interpretations and meanings revealed in the readings are based on the ancient mysteries of Tarot cards and Runes, but they may not always be accurate for every fate or situation.</p>            <p>This bot channels revelations through the mystical power of artificial intelligence, yet it does not possess true psychic abilities and cannot predict the future with absolute certainty. It is important to remember that the accuracy of each revelation cannot be guaranteed, and its meaning may be multifaceted.</p>            <p>Users should approach each revelation with wisdom, considering all possible paths and making decisions with caution. Fate-altering choices should not be made based solely on the charms spoken by this bot.</p>            <p>This service cannot replace consultation with wise mentors—lawyers, financial advisors, therapists, or other individuals with official authority. Seek true experts if your soul requires guidance on important life matters.</p>            <p>The creators and operators of this bot are not responsible for the truth or outcome of the revelations received. The use of this service is at your own discretion and risk</p>            <p>By requesting or receiving predictions from this service, the user acknowledges that all readings are created solely for entertainment and mystical exploration. The user agrees not to hold the creators or operators of this bot accountable for any interpretations or prophecies`,Disclaimer:``,"Privacy Policy":``,"Privacy Policy-text":`<h2>Privacy Policy</h2><p>This privacy policy outlines how tell.guru collects, uses, and shares your personal information when you visit our website or use our Tarot and Rune reading services.</p><h2>Information We Collect</h2><p>When you sign in to our service using your Google account, we collect your email address from your Google profile. This information is used solely for authentication and to create a unique user ID for your tell.guru account. We do not collect or store any other personal information, such as your name or other profile details.</p><h2>How We Use Your Information</h2><p>We use the email address from your Google profile as a unique identifier for your tell.guru account. We do not use your email address for marketing purposes, nor do we share it with third parties.</p><h2>How We Share Your Information</h2><p>We do not share, sell, or disclose any personal information to third parties or external companies. The only information shared is aggregate data about site usage, which does not contain personally identifiable details.</p><h2>Data Storage and Security</h2><p>Email addresses collected for tell.guru accounts are stored in a secure database protected by industry-standard security measures, including encryption and firewalls. We prioritize the security of your data and ensure that email addresses are only used as unique identifiers, not linked to passwords, profile data, usage statistics, or reading results.</p><h2>Changes to This Privacy Policy</h2><p>We may update this privacy policy from time to time. If significant changes are made, we will notify you via email or by posting a prominent notice on our website. Any updates will be reflected by revising the date at the top of this policy. We encourage you to review this policy regularly to stay informed about our practices.</p><h2>Contact Us</h2><p>If you have any questions regarding this privacy policy or our services, please contact us at <a href="mailto:info@tell.guru">info@tell.guru</a>.</p><p>Thank you for choosing tell.guru for your Tarot and Rune reading experience.</p>`,"Terms of Service":``,"Terms of Service-text":` <h2>Terms of Service</h2>           <p><strong>Last Update:</strong> January 25, 2025.</p>            <p>Welcome to the tell.guru website! Please carefully read our Terms of Service before using our services. By accessing and using this website, you agree to be bound by the terms outlined below.</p>           <h2>Service Description:</h2>            <p>tell.guru provides Tarot and Rune readings powered by AI, utilizing images, texts, and code developed by the site’s owner to automate the reading process.</p>            <h2>Rules of Use:</h2>             <p>By using our service, you agree to comply with all applicable laws and regulations.</p>             <p>The use of the site for illegal, harmful, or disruptive activities is strictly prohibited.</p>            <h2>Intellectual Property:</h2>             <p>All images, texts, and code provided on the site are the intellectual property of the site owner.</p>             <p>Unauthorized use or reproduction of these materials is prohibited.</p>           <h2>Confidentiality:</h2>            <p>We value your privacy. Any personal information we collect is handled in accordance with our <a href="#">Privacy Policy</a>.</p>            <h2>Disclaimer:</h2>            <p>The site owner is not responsible for the results of Tarot or Rune readings provided by the AI. Use of the site and the information provided is at your own risk.</p>            <h2>Changes to Terms:</h2>           <p>The site owner reserves the right to update or modify these Terms of Service at any time. Any changes will become effective immediately upon publication on the site.</p>            <h2>Contact:</h2>            <p>If you have any questions or concerns regarding these Terms of Service, please contact us at: <a href="mailto:info@tell.guru">info@tell.guru</a>.</p>            <p>By using tell.guru, you acknowledge that you have read, understood, and agreed to these terms. Thank you for visiting our site!</p>`,Choice:`Crossroads`,About:`About`,Rules:`Rules`,"nav-help":`Grimoire`,"nav-path":`Path`,"nav-tarot":`Tarot`,"nav-runes":`Runes`,"nav-faq":`FAQ`,"nav-login":`Login`,"nav-contact":`Contact Me`,"Contact Us":`Contact Us`,"Summon the Author":`Summon the Author`,"Contact Form":`Contact Form`,"First Name":`First Name`,"Last Name":`Last Name`,Subject:`Subject`,Message:`Message`,"Write your notes or questions here...":`Send a sign to the author through the threads of fate...`,"Send Message":`Send Message`,"Sending...":`Sending...`,Sent:`Sent`,Error:`Error`,Password:`Password`,"Incorrect email or password":`Incorrect email or password`,"Log out":`Log out`,"Sign up":`Sign up`,"Create account":`Create account`,"Back to Login":`Back to Login`,"nav-choose-path":`Walk Your Chosen Path`,"nav-tarot-sub":`Cards of Fate`,"nav-tarot-hint":`78 arcana unveil the hidden truths`,"nav-runes-sub":`Signs of the Ancients`,"nav-runes-hint":`Runes carry the wisdom of ages`,"nav-faq-sub":`Answers hidden between the lines`,"nav-rules-sub":`The laws that bind the unseen`},i={"welcome-text":`Это врата в загадочный мир, где встречаются две великие мистические силы – Таро и Руны. Древние ключи хранят ответы на тайны судьбы и шепчут голосами вселенной. Что выберете вы: мудрость таинственных карт Таро или магию древних рунных символов? Сделайте шаг навстречу неведомому, окунитесь в поток предсказаний, и позвольте искусственному интеллекту стать вашим проводником в лабиринте судеб и тайн.`,"welcome-advice-fallback":`Звезды уже шепчут, и твой путь раскрывается шаг за шагом.`,"welcome-advice-label":`Шепот судьбы на сегодня`,"welcome-subtitle":`Мистическое приветствие цифрового Оракула ИИ`,"welcome-title-start":`Мистический оракул`,"welcome-title-end":`готов открыть тайны`,"tarot-label":`ТАРО`,"runes-label":`РУНЫ`,"welcome-title":`Приветствие из мира тайн вашего Оракула ИИ!`,"what speak":`Что откликается в глубинах души?`,"two-paths":`Перед тобой два пути, как перекрёстки судьбы. Один ведёт через слова мудрецов, другой – через древнюю силу символов. Какой путь ты выберешь? Или, быть может, осмелишься исследовать оба и раскрыть их тайны?`,"tarot-text":`Карты Таро — это язык древних архетипов, сплетающий нити прошлого, настоящего и будущего. Войдите в мир, где каждая карта — это глава вашей истории, ожидающая своего раскрытия.
Через символы, образы и скрытые смыслы Таро отражает силы, формирующие вашу жизнь, и выборы, стоящие перед вами. Каждый расклад — это зеркало вашего пути, дарующее подсказки, понимание и проблеск невидимых нитей судьбы.
Вытяните карты и узнайте, какую историю готов раскрыть этот момент.`,"tarot-welcome-text":`Древние карты Таро несут в себе мудрость веков. Они раскрывают скрытые течения судьбы и помогают находить ответы.`,"rune-welcome-text":`Рунические символы несут древнюю мудрость. Их послание меняется, словно ветры судьбы, следуя за вопросом, который не отпускает ваши мысли.`,"chosen-rune":`Выберите руну`,"random-rune":`Позволь судьбе выбрать`,"Random rune":`Открой свою руну`,"shuffle-runes":`Перемешать руны`,"Get prediction":`Получить предсказание`,"runes-no-selection":`Выберите руну, чтобы услышать её шепот.`,"Rune-welcome":`Судьба высечена в рунах`,"Make your choice":`Призови свою судьбу:`,"Daily Tarot":`Расклад на день`,"3 Cards Tarot":`Расклад на 3 карты`,"Personal reading":`Персональное гадание`,"tarot-pos-past":`Прошлое`,"tarot-pos-present":`Настоящее`,"tarot-pos-future":`Будущее`,Love:`Любовь`,Relationship:`Отношения`,Money:`Деньги`,Business:`Бизнес`,Telling:`Значение`,"tarot-error":`Оракул пока молчит. Попробуй ещё раз через мгновение.`,"rune-error":`Руны пока молчат. Попробуйте еще раз через мгновение.`,"Tarot Experiences Await":`Опыт Таро ждет вас`,"How to":`Инструкции`,"Explore Tarot":`Искусство использования бота с помощью нашего подробного руководства.`,"Explore More":`Детальнее`,"daily subscribe":`Подписка`,"daily subscribe button":`Что готовит будущий день? Ежедневное предсказание по карте Таро прямо на email.`,"TG bot":`Телеграм бот`,"TG text button":`Испытайте волшебство чтений Таро с помощью нашего бота Telegram!`,"How to use:":`Как пользоваться:`,"Guidance:":`Наставление`,"slide.kicker":`Тип расклада`,"slide1.title":`Карта дня`,"slide1.text":`
Сконцентрируйся на своём внутреннем вопросе.<br>
Позволь тишине говорить.<br>
Коснись карты — и она откроется тебе.<br>
Прими её послание… и наблюдай, как оно проявится.
`,"slide2.title":`Три карты`,"slide2.text":`
Задай вопрос, который давно живёт внутри.<br>
Выбери три карты.<br><br>

<strong>Первая</strong> — то, что уже сплелось в судьбе.<br>
<strong>Вторая</strong> — то, что раскрывается сейчас.<br>
<strong>Третья</strong> — то, что приближается к тебе.
`,"slide3.title":`Персональный расклад`,"slide3.text":`
Выбери слово, которое зовёт тебя.<br>
Задержись в этом ощущении.<br>
Позволь посланию прийти.<br>
Истина откликнется там, где ты её почувствуешь.
`,"slide1.name":`Наставление`,"reflect.title":`Размышление`,"reflect.text":`Поразмышляйте над информацией, полученной из значения карт. Подумайте, как вы можете использовать эти знания, чтобы принимать более осознанные решения и делать уместные шаги в тех сферах жизни, которых коснулся расклад. Помните, что гадание на Таро - это инструмент для самоанализа и личного понимания. Доверяйте своей интуиции и используйте карты как источник наставления, а не как окончательное предсказание будущего.`,"subscription-text":`<h2>Вселенная готова открыть свои тайны.</h2><p>Подпишись и получай ежедневные пророчества Таро прямо на email.</p>`,"Manage subscription":`Управление подпиской`,"Subscribe for Daily Tarot":`Подписка на ежедневное Таро`,"TG text":`<h1>Присоединяйтесь к нам в Telegram</h1><p>И откройте дверь в мир тайн и волшебства Таро! Получите уникальные гадания, исследуйте Арканы и насладитесь волшебным путешествием в мир древней мудрости и вдохновения.</p>`,"daily-next":`Карта дня будет доступна в {time}`,"Stay connected text":`<p>Загляните на наш <a href="https://www.buymeacoffee.com/mnimi" target="_blank">Buy Me a Coffee</a> и добавьте каплю магии в наш котёл гаданий. Ваша поддержка помогает энергии предсказаний свободно течь и даёт мистике расцветать!</p><p>Станьте частью чар — и магия обязательно вернётся к вам!</p>`,"rune-text":`Руны — это голос северных ветров и древней земли. Они говорят не словами, а вечными символами, ведя к истине через шёпот веков.
Каждая руна несёт отголосок забытой мудрости — знак, высеченный из мифов, судьбы и глубоких течений предназначения. Когда руны брошены, они открывают узоры, скрытые под поверхностью вашего вопроса, освещая пути, которые вы могли ещё не увидеть.
Прислушайтесь — в их безмолвном языке до сих пор звучит сила древних времён.`,"soul-prev":`Вернуться к знаку прошлого`,"soul-next":`Следовать за новым знамением`,"soul-open-tarot":`Разложить Таро`,"soul-open-runes":`Вопросить руны`,"soul-inscription-tarot":`✦ АРКАНЫ · ГАДАНИЕ · ДОЛЯ ✦`,"soul-inscription-runes":`✦ ФУТАРК · МУДРОСТЬ СЕВЕРА · СУДЬБА ✦`,faq:`FAQ (Тайны, о которых вы хотите узнать)`,"How do predictions work?":`Как работают предсказания?`,"how do predictions work-text":`Когда вы делаете выбор, вы словно перелистываете страницу своей судьбы. И наш ИИ лишь помогает вам прочитать то, что уже написано тонкими линиями времени.`,"Tarot or Runes: which is more accurate?":`Таро или Руны: что точнее?`,"Tarot or Runes: which is more accurate-text":`Таро — это зеркало души, раскрывающее, что скрыто внутри, открывающее глубины ваших эмоций и желаний. Руны, в свою очередь, — это компас, который направляет вас на ваш путь, даруя ясность, когда вы теряетесь, и освещая дорогу в моменты неопределенности. Каждый инструмент хранит свою истину в правильных руках — или в руках нашего ИИ.`,"How can I begin a reading?":`Как начать гадание?`,"How can I begin a reading-text":`Просто кликните на картинку, и древние силы оживут. Не нужно шаманить или доставать хрустальный шар — всё уже готово!`,"Can I do multiple readings?":`Могу ли я гадать несколько раз?`,"Can I do multiple readings-text":`Конечно! Каждый раз — это как новая глава в вашей книге. Чем больше вы спрашиваете, тем больше страниц открывается.`,"What if I don't know what to ask?":`А что, если я не знаю, что спросить?`,"What if I don't know what to ask-text":`Не волнуйтесь, судьба знает, что вам нужно. Задайте любой вопрос, даже самый простой, и получите ответ, который вы так давно искали.`,"Is it free?":`Это бесплатно?`,"Is it free-text":`Да, древняя магия на службе у технологий нашем сайте бесплатна для всех искателей. Для тех, кто хочет углубиться, мы предлагаем дополнительные услуги, такие как подписка или доступ к нашему мистическому Telegram-каналу за символическую плату. Ваша поддержка питает чары и помогает нам творить ещё больше волшебства!`,"How accurate are the predictions?":`Насколько точны предсказания?`,"How accurate are the predictions-text":`Мудрость древних + мощь искусственного интеллекта = попадание в десятку. Хотя иногда судьба любит поиграть в загадки.`,"What if I don't like the answer-text":`Судьба иногда говорит горькую правду. Но помните: ответы — это только направление, а решение остаётся за вами.`,"What if I don't like the answer?":`Что делать, если мне не понравился ответ?`,"About this project":`О проекте`,"About this project-text":`<p>Добро пожаловать в портал, где древние символы встречаются с современными технологиями.</p><p>Здесь вечные языки Таро и Рун исследуются с помощью искусственного интеллекта — создавая цифрового оракула, соединяющего древние традиции и современный код.</p><p>Этот проект является частью моего академического пути в мире разработки программного обеспечения.</p><p>Считайте его песочницей для экспериментов, где я исследую идеи, технологии и творческие способы объединения сторителлинга, символизма и искусственного интеллекта.</p><p>Каждая строка кода здесь — это и практика, и любопытство: попытка увидеть, как технологии могут дать новую форму древним мистическим системам.</p><p>Если вы изучаете эту страницу как часть моего портфолио — добро пожаловать.</p><p>А если вы здесь просто из любопытства — <a class="rich-link" href="/tarot">пусть карты говорят</a>, а <a class="rich-link" href="/runes">руны шепчут</a>.</p><p>✨ Пусть символы ведут вас. ✨</p>`,"Paths and Laws of Fate":`Пути и Законы Судьбы`,"Paths and Laws of Fate-text-1":`Показания Таро и Рун, вознесенные этим мистическим инструментом, предназначены исключительно для погружения в мир магии и развлечений. Они не должны восприниматься как профессиональные пророчества или предсказания неизбежных событий.`,"Paths and Laws of Fate-text-2":`<p>Все интерпретации и значения, раскрытые в раскладах, основаны на древних таинствах карт Таро и древних Рун, но не всегда они могут быть точны для каждой судьбы или ситуации.</p><p>Этот бот вызывает откровения через мистическую силу искусственного интеллекта, однако, он не обладает истинными экстрасенсорными способностями и не может предсказать будущее с абсолютной точностью. Весьма важно помнить, что точность каждого откровения нельзя гарантировать, и его значение может быть многозначным.</p><p>Пользователи должны подходить к каждому откровению с мудростью, учитывая все возможные пути и принимая решения с осторожностью. Не следует делать судьбоносные выборы, опираясь исключительно на чары, произнесенные этим ботом.</p><p>Эта служба не может заменить консультацию с мудрыми наставниками — юристами, финансовыми советниками, терапевтами или иными лицами с официальными полномочиями. Обратитесь к истинным экспертам, если ваша душа ищет совет по важным вопросам жизни.</p><p>Создатели и операторы этого бота не несут ответственности за истину или результат полученных откровений. Использование этой услуги происходит на ваше усмотрение и риск.</p><p>Запрашивая или принимая откровения от этого бота, пользователь признает, что все показания созданы исключительно для развлечения и мистического исследования. Пользователь соглашается не возлагать ответственность на создателей и операторов этого бота за любые интерпретации или пророчества.</p>`,Disclaimer:`Oтказ от ответственности`,"Privacy Policy-text":`<h2>Политика конфиденциальности</h2><p>Данная политика конфиденциальности описывает, как tell.guru собирает, использует и передает вашу личную информацию при посещении нашего сайта или использовании наших услуг по гаданию на Таро и Рунах.</p><h2>Информация, которую мы собираем</h2><p>Когда вы входите в нашу службу с помощью вашей учетной записи Google, мы собираем ваш адрес электронной почты из вашего профиля Google. Эта информация используется исключительно для аутентификации и создания уникального идентификатора пользователя для вашей учетной записи tell.guru. Мы не собираем и не храним другие личные данные, такие как ваше имя или другие данные профиля.</p><h2>Как мы используем вашу информацию</h2><p>Мы используем адрес электронной почты из вашего профиля Google как уникальный идентификатор для вашей учетной записи tell.guru. Мы не используем ваш адрес электронной почты в маркетинговых целях и не передаем его третьим лицам.</p><h2>Как мы делимся вашей информацией</h2><p>Мы не передаем, не продаем и не раскрываем вашу личную информацию третьим сторонам или внешним компаниям. Единственная информация, которую мы делимся, — это агрегированные данные о посещении сайта, не содержащие персонально идентифицируемых данных.</p><h2>Хранение данных и безопасность</h2><p>Адреса электронной почты, собранные для учетных записей tell.guru, хранятся в защищенной базе данных, защищенной стандартными мерами безопасности, такими как шифрование и брандмауэры. Мы придаем большое значение безопасности ваших данных и гарантируем, что адреса электронной почты используются только в качестве уникальных идентификаторов, не связанных с паролями, данными профиля, статистикой использования или результатами гадания.</p><h2>Изменения в данной политике конфиденциальности</h2><p>Мы можем периодически обновлять данную политику конфиденциальности. В случае значительных изменений мы уведомим вас по электронной почте или разместим заметное уведомление на нашем сайте. Все обновления будут отражены путем изменения даты в верхней части этой политики. Мы рекомендуем вам регулярно проверять эту политику, чтобы быть в курсе наших практик.</p><h2>Свяжитесь с нами</h2><p>Если у вас есть вопросы по данной политике конфиденциальности или нашим услугам, пожалуйста, свяжитесь с нами по адресу <a href="mailto:info@tell.guru">info@tell.guru</a>.</p><p>Спасибо, что выбрали tell.guru для вашего опыта гадания на Таро и Рунах.</p>`,"Terms of Service-text":` <h2>Условия использования</h2>           <p><strong>Дата последнего обновления:</strong> Январь 25, 2025.</p>            <p>Добро пожаловать на сайт tell.guru! Пожалуйста, внимательно ознакомьтесь с нашими Условиями использования перед тем, как использовать наши услуги. Получив доступ и используя этот сайт, вы соглашаетесь с условиями, изложенными ниже.</p>           <h2>Описание услуги:</h2>            <p>tell.guru предоставляет гадания на картах Таро и Рунах с помощью ИИ, используя изображения, тексты и код, разработанные владельцем сайта для автоматизации процесса гадания.</p>            <h2>Правила использования:</h2>             <p>Используя наш сервис, вы соглашаетесь соблюдать все применимые законы и нормативные акты.</p>             <p>Использование сайта для незаконных, вредоносных или разрушительных целей строго запрещено.</p>            <h2>Интеллектуальная собственность:</h2>             <p>Все изображения, тексты и код, размещенные на сайте, являются интеллектуальной собственностью владельца сайта.</p>             <p>Неавторизованное использование или воспроизведение этих материалов запрещено.</p>           <h2>Конфиденциальность:</h2>            <p>Мы ценим вашу конфиденциальность. Личная информация, которую мы собираем, обрабатывается в соответствии с нашей <a href="#">Политикой конфиденциальности</a>.</p>            <h2>Отказ от ответственности:</h2>            <p>Владелец сайта не несет ответственности за результаты гаданий на картах Таро или Рунах, предоставленных ИИ. Использование сайта и предоставленной информации происходит на ваш собственный риск.</p>            <h2>Изменения в условиях:</h2>           <p>Владелец сайта оставляет за собой право обновлять или изменять эти Условия использования в любое время. Изменения вступают в силу сразу после публикации на сайте.</p>            <h2>Контакты:</h2>            <p>Если у вас есть вопросы или замечания относительно этих Условий использования, пожалуйста, свяжитесь с нами по адресу: <a href="mailto:info@tell.guru">info@tell.guru</a>.</p>            <p>Используя tell.guru, вы подтверждаете, что ознакомились с этими условиями и согласны с ними. Спасибо, что посетили наш сайт!</p>`,Rules:`Правила`,Choice:`Перекресток`,About:`О проекте`,"nav-help":`Знания`,"nav-path":`Путь`,"nav-tarot":`Таро`,"nav-runes":`Руны`,"nav-faq":`FAQ`,"nav-login":`Вход`,"nav-contact":`Связаться со мной`,"Contact Us":`Связаться с нами`,"Summon the Author":`Призвать автора`,"Contact Form":`Форма связи`,"First Name":`Имя`,"Last Name":`Фамилия`,Email:`Email`,Subject:`Тема`,Message:`Сообщение`,"Write your notes or questions here...":`Отправь знак автору через нити судьбы...`,"Send Message":`Отправить сообщение`,"Sending...":`Отправка...`,Sent:`Отправлено`,Error:`Ошибка`,Password:`Пароль`,"Incorrect email or password":`Неверный email или пароль`,"Log out":`Выйти`,"Sign up":`Регистрация`,"Create account":`Создать аккаунт`,"Back to Login":`Назад ко входу`,"Stay Connected":`Магия на кончиках пальцев! `,"Hello, adventurer":`Привет, странник`,"Your telling:":`Таинственные Знамения:`,"nav-choose-path":`Ступи на свой путь`,"nav-tarot-sub":`Карты Судьбы`,"nav-tarot-hint":`78 арканов приоткроют завесу тайн`,"nav-runes-sub":`Знаки Древних`,"nav-runes-hint":`Руны хранят мудрость веков`,"nav-faq-sub":`Ответы, сокрытые между строк`,"nav-rules-sub":`Законы, что связывают незримое`},a={"welcome-text":`Прямо зараз розчинились ворота у світ таємничого, де зустрічаються дві величні містичні сили – Таро та Руни. Ці древні ключі зберігають відповіді на загадки долі та шепочуть голосами всесвіту. Що оберете ви: мудрість загадкових карт Таро чи магію стародавніх рунічних символів? Зробіть крок у невідоме, зануртеся у потік пророцтв і дозвольте штучному інтелекту стати вашим провідником у лабіринті таємниць і долі.`,"welcome-advice-fallback":`Зорі вже шепочуть, а твій шлях розкривається крок за кроком.`,"welcome-advice-label":`Шепіт долі на сьогодні`,"welcome-subtitle":`Містичне вітання цифрового Оракула ШІ`,"welcome-title-start":`Оракул`,"welcome-title-end":`, готовий відкрити таємниці`,"tarot-label":`ТАРО`,"runes-label":`РУНИ`,"welcome-title":`Привітання із світу таємниць від вашого Оракула ШІ!`,"what speak":`Що шепоче душі всесвіт?`,"two-paths":`Перед тобою два шляхи, немов перехрестя долі. Один веде крізь слова оповідачів, інший – через древню мудрість символів. Який шлях вибереш ти? А може, наважишся пройти обома і відкрити їхні таємниці?`,"tarot-text":`Карти Таро — це мова давніх архетипів, що сплітає нитки минулого, теперішнього й майбутнього. Увійдіть у світ, де кожна карта — це розділ вашої історії, який чекає на своє відкриття.
Через символи, образи й приховані значення Таро відображає сили, що формують ваше життя, та вибори, які стоять перед вами. Кожен розклад — це дзеркало вашого шляху, що дарує підказки, розуміння і проблиск невидимих ниток долі.
Витягніть карти й дізнайтеся, що історія цього моменту готова відкрити.`,"tarot-welcome-text":`Древні карти Таро несуть у собі мудрість століть. Вони розкривають приховані течії долі та допомагають знаходити відповіді.`,"rune-welcome-text":`Рунічні символи несуть давню мудрість. Їхнє послання змінюється, мов вітри долі, й відгукується на питання, що не полишає ваших думок.`,"chosen-rune":`Оберіть руну`,"random-rune":`Дозволь долі обрати за вас`,"Random rune":`Випадкова руна`,"shuffle-runes":`Перемішати руни`,"Get prediction":`Отримати передбачення`,"runes-no-selection":`Оберіть руну, щоб почути її шепіт.`,"Rune-welcome":`Долю викарбувано в рунах`,"Make your choice":`Дозволь картам розкрити твою долю:`,"Daily Tarot":`Розклад на день`,"3 Cards Tarot":`Розклад на 3 карти`,"Personal reading":`Персональне ворожіння`,"tarot-pos-past":`Минуле`,"tarot-pos-present":`Теперішнє`,"tarot-pos-future":`Майбутнє`,Love:`Кохання`,Relationship:`Відносини`,Money:`Гроші`,Business:`Бізнес`,Telling:`Тлумачення`,"Your telling:":`Ваші пророцтва:`,"tarot-error":`Оракул мовчить. Спробуй ще раз за мить.`,"rune-error":`Руни поки мовчать. Спробуйте ще раз за мить.`,"Tarot Experiences Await":`Досвід Таро чекає`,"How to":`Інструкції`,"Explore Tarot":`Мистецтво використання бота з нашим вичерпним посібником та секрети ефективного читання Таро.`,"Explore More":`Більше`,"daily subscribe":`Підписка`,"daily subscribe button":`Що готує для тебе цей день? Щоденне передбачення за допомогою карти Таро просто на email.`,"TG bot":`Телеграм бот`,"TG text button":`Відчуйте магію читання Таро на нашому боті Telegram!.`,"How to use:":`Як користуватися:`,"Guidance:":`Настанова`,"slide.kicker":`Тип розкладу`,"slide1.title":`Карта дня`,"slide1.text":`
Зосередься на своєму внутрішньому питанні.<br>
Дозволь тиші промовляти.<br>
Торкнися карти — і вона відкриється тобі.<br>
Прийми її послання… і спостерігай, як воно проявляється.
`,"slide2.title":`Три карти`,"slide2.text":`
Постав питання, що давно живе всередині.<br>
Обери три карти.<br><br>

<strong>Перша</strong> — те, що вже сплелося у долі.<br>
<strong>Друга</strong> — те, що розкривається зараз.<br>
<strong>Третя</strong> — те, що наближається до тебе.
`,"slide3.title":`Персональний розклад`,"slide3.text":`
Обери слово, що кличе тебе.<br>
Затримайся в цьому відчутті.<br>
Дозволь посланню прийти.<br>
Істина відгукнеться там, де ти її відчуєш.
`,"slide1.name":`Настанова`,"reflect.title":`Роздуми`,"reflect.text":`Поміркуйте над інформацією, отриманою зі значення карт. Подумайте, як ви можете використати ці знання, щоб ухвалювати більш усвідомлені рішення та робити доречні кроки в тих сферах життя, яких торкнувся розклад. Пам'ятайте, що ворожіння на Таро - це інструмент для самоаналізу та особистого розуміння. Довіряйте своїй інтуїції й використовуйте карти як джерело настанови, а не як остаточне передбачення майбутнього.`,"subscription-text":`<h2>Всесвіт готовий відкрити свої таємниці.</h2><p>Підпишись та отримуй щоденні пророцтва Таро на email.</p>`,"Manage subscription":`Керувати підпискою`,"Subscribe for Daily Tarot":`Підписка на щоденне Таро`,"TG text":`<h1>Приєднуйтесь до нас у Telegram</h1><p>Та відкрийте двері у світ таємниць і магії Таро! Отримайте унікальне ворожіння, досліджуйте Аркани та насолоджуйтесь чарівною подорожжю у світ стародавньої мудрості та натхнення.</p>`,"daily-next":`Карта дня буде доступна о {time}`,"Stay Connected":`Магія у ваших руках!`,"Stay connected text":`<p>Зазирніть на наш <a href="https://www.buymeacoffee.com/mnimi" target="_blank">Buy Me a Coffee</a> і додайте краплинку магії до нашого казана пророцтв. Ваша підтримка наповнює енергію ворожінь життям, а світ містики — розквітає ще яскравіше!</p><p>Станьте частиною чарів, і магія обов’язково повернеться до вас!</p>`,"rune-text":`Руни — це голос північних вітрів і давньої землі. Вони говорять не словами, а вічними символами, ведучи до істини крізь шепіт віків.
Кожна руна несе відлуння забутої мудрості — знак, викарбуваний із міфів, долі та глибинних потоків призначення. Коли руни кидають, вони відкривають візерунки, приховані під поверхнею вашого питання, освітлюючи шляхи, які ви могли ще не помітити.
Прислухайтеся уважно — у їхній мовчазній мові й досі звучить сила давніх часів.`,"soul-prev":`Повернутися до знаку минулого`,"soul-next":`Йти за новим знаменням`,"soul-open-tarot":`Розкласти Таро`,"soul-open-runes":`Звернутися до рун`,"soul-inscription-tarot":`✦ АРКАНИ · ВОРОЖІННЯ · СИЛА ✦`,"soul-inscription-runes":`✦ ФУТАРК · МУДРІСТЬ ПІВНОЧІ · ДОЛЯ ✦`,faq:`FAQ (Таємниці, які ви прагнете розкрити)`,"How do predictions work?":`Як працюють пророцтва?`,"how do predictions work-text":`Коли ви робите вибір, це ніби перегортаєте сторінку своєї долі. Наш ШІ лише допомагає вам прочитати те, що вже вплетено в тонкі ниті часу.`,"Tarot or Runes: which is more accurate?":`Таро чи Руни: що точніше?`,"Tarot or Runes: which is more accurate-text":`Таро — це дзеркало душі, що розкриває те, що приховано всередині, відкриваючи глибини ваших емоцій та бажань. Руни ж, у свою чергу, є компасом, що веде вас на ваш шлях, даруючи ясність, коли ви відчуваєте себе загубленими, і освітлюючи шлях через невизначеність. Кожен інструмент тримає свою істину в правильних руках — або в руках нашого ІІ.`,"How can I begin a reading?":`Як розпочати ворожіння?`,"How can I begin a reading-text":`Просто натисніть на зображення, і давні сили оживуть. Не потрібно проводити ритуали чи шукати кришталеву кулю — усе вже готове для вас!`,"Can I do multiple readings?":`Чи можу я гадати кілька разів?`,"Can I do multiple readings-text":`Звісно! Кожне ворожіння — це як нова глава вашої історії. Що більше ви питаєте, то більше сторінок вашої долі відкривається.`,"What if I don't know what to ask?":`А що, якщо я не знаю, що запитати?`,"What if I don't know what to ask-text":`Не хвилюйтесь — доля знає, що вам потрібно. Задайте будь-яке запитання, навіть найпростіше, і отримаєте відповідь, яку так довго шукали.`,"Is it free?":`Чи це безкоштовно?`,"Is it free-text":`Так, давня магія на службі у технологій на нашому сайті безкоштовна для всіх шукачів. Для тих, хто прагне заглибитися, ми пропонуємо додаткові послуги, як-от підписка на щоденну карту з пророцтвами або доступ до нашого містичного Telegram-каналу за символічну плату. Ваша підтримка живить чари та допомагає нам творити ще більше магії!`,"How accurate are the predictions?":`Наскільки точні пророцтва?`,"How accurate are the predictions-text":`Мудрість предків + потужність штучного інтелекту = попадання в ціль. Хоча інколи доля любить грати в загадки.`,"What if I don't like the answer-text":`Доля інколи говорить гірку правду. Але пам’ятайте: відповіді — це лише напрямок, а рішення залишається за вами.`,"What if I don't like the answer?":`Що робити, якщо мені не сподобалась відповідь?`,"About this project":`Про проект`,"About this project-text":`<p>Ласкаво прошу до порталу, де давні символи зустрічаються із сучасними технологіями.</p><p>Тут позачасові мови Таро та Рун досліджуються за допомогою штучного інтелекту — створюючи цифрового оракула, що поєднує давні традиції та сучасний код.</p><p>Цей проєкт є частиною мого академічного шляху у світ розробки програмного забезпечення.</p><p>Сприймайте його як пісочницю для експериментів, де я досліджую ідеї, технології та творчі способи поєднання сторітелінгу, символізму та штучного інтелекту.</p><p>Кожен рядок коду тут — це і практика, і цікавість: спроба побачити, як технології можуть надати нову форму давнім містичним системам.</p><p>Якщо ви переглядаєте цю сторінку як частину мого портфоліо — ласкаво прошу.</p><p>А якщо ви тут просто з цікавості — <a class="rich-link" href="/tarot">нехай карти говорять</a>, а <a class="rich-link" href="/runes">руни шепочуть</a>.</p><p>✨ Нехай символи ведуть вас. ✨</p>`,"Paths and Laws of Fate":`Шляхи та Закони Долі`,"Paths and Laws of Fate-text-1":`Інтерпретації карт Таро та рун, піднесені цим містичним інструментом, призначені виключно для занурення у світ магії та розваг. Їх не слід сприймати як професійні пророцтва чи передбачення неминучих подій.`,"Paths and Laws of Fate-text-2":`<p>Усі інтерпретації та значення, розкриті в читаннях, базуються на давніх таємницях карт Таро і Рун, але вони можуть не завжди бути точними для кожної долі чи ситуації.</p>            <p>Цей бот передає одкровення через містичну силу штучного інтелекту, але він не володіє справжніми психічними здібностями і не може передбачити майбутнє з абсолютною точністю. Важливо пам’ятати, що точність кожного одкровення не може бути гарантована, а його значення може бути багатогранним.</p>
            <p>Користувачі повинні підходити до кожного одкровення з мудрістю, розглядаючи всі можливі шляхи і приймаючи рішення з обережністю. Рішення, які змінюють долю, не слід приймати лише на основі чарівності, озвученої цим ботом.</p>            <p>Ця служба не може замінити консультацію з мудрими наставниками — юристами, фінансовими консультантами, терапевтами чи іншими особами з офіційною компетенцією. Звертайтеся до справжніх експертів, якщо ваша душа потребує порад з важливих життєвих питань.</p>            <p>Творці та оператори цього бота не несуть відповідальності за правдивість або результат одкровень, отриманих через нього. Використання цієї служби здійснюється на ваш власний розсуд і ризик.</p>            <p>Замовляючи або отримуючи одкровення через цей скрвіс, користувач визнає, що всі читання створені виключно для розваг і містичного дослідження. Користувач погоджується не притягати творців чи операторів цього бота до відповідальності за будь-які інтерпретації чи пророцтва.</p>`,Disclaimer:`Відмова від відповідальності`,"Privacy Policy":``,"Privacy Policy-text":`<h2>Політика конфіденційності</h2>        <p>Ця політика конфіденційності описує, як tell.guru збирає, використовує та передає вашу особисту інформацію під час відвідування нашого вебсайту або використання наших послуг для ворожіння на Таро та Рунах.</p>        <h2>Інформація, яку ми збираємо</h2>        <p>Коли ви входите в наш сервіс за допомогою вашого облікового запису Google, ми збираємо вашу електронну адресу з вашого профілю Google. Ця інформація використовується виключно для автентифікації та створення унікального ідентифікатора користувача для вашого облікового запису tell.guru. Ми не збираємо і не зберігаємо іншу особисту інформацію, таку як ваше ім’я чи інші дані профілю.</p>        <h2>Як ми використовуємо вашу інформацію</h2>        <p>Ми використовуємо електронну адресу з вашого профілю Google як унікальний ідентифікатор для вашого облікового запису tell.guru. Ми не використовуємо вашу електронну адресу для маркетингових цілей і не передаємо її третім сторонам.</p>        <h2>Як ми ділимося вашою інформацією</h2>        <p>Ми не передаємо, не продаємо і не розкриваємо вашу особисту інформацію третім сторонам чи зовнішнім компаніям. Єдина інформація, яку ми передаємо — це агреговані дані про використання сайту, які не містять персонально ідентифікованих даних.</p>        <h2>Зберігання даних і безпека</h2>        <p>Електронні адреси, зібрані для облікових записів tell.guru, зберігаються в захищеній базі даних, захищеній стандартними заходами безпеки, такими як шифрування та брандмауери. Ми надаємо великого значення безпеці ваших даних і гарантуємо, що електронні адреси використовуються лише як унікальні ідентифікатори, не пов'язані з паролями, даними профілю, статистикою використання чи результатами ворожінь.</p>        <h2>Зміни в цій політиці конфіденційності</h2>        <p>Ми можемо періодично оновлювати цю політику конфіденційності. Якщо будуть внесені значні зміни, ми повідомимо вас через електронну пошту або розмістимо помітне повідомлення на нашому вебсайті. Усі оновлення будуть відображені шляхом зміни дати вгорі цієї політики. Ми рекомендуємо регулярно перевіряти цю політику, щоб бути в курсі наших практик.</p>        <h2>Зв'яжіться з нами</h2>        <p>Якщо у вас є питання щодо цієї політики конфіденційності або наших послуг, будь ласка, зв'яжіться з нами за адресою <a href="mailto:info@tell.guru">info@tell.guru</a>.</p>        <p>Дякуємо, що обрали tell.guru для вашого досвіду ворожінь на Таро та Рунах.</p>`,"Terms of Service":``,"Terms of Service-text":` <h2>Умови використання</h2>           <p><strong>Останнє оновлення:</strong> Січень 25, 2025.</p>            <p>Ласкаво просимо на сайт tell.guru! Будь ласка, уважно ознайомтесь з нашими Умовами використання перед тим, як скористатися нашими послугами. Використовуючи цей сайт, ви погоджуєтесь з умовами, викладеними нижче.</p>           <h2>Опис послуги:</h2>            <p>tell.guru надає гадання на картах Таро та Рунах за допомогою ШІ, використовуючи зображення, тексти та код, розроблені власником сайту для автоматизації процесу гадання.</p>            <h2>Правила використання:</h2>             <p>Використовуючи наш сервіс, ви погоджуєтесь дотримуватись усіх застосовних законів та нормативних актів.</p>             <p>Використання сайту для незаконних, шкідливих чи руйнівних цілей суворо заборонено.</p>            <h2>Інтелектуальна власність:</h2>             <p>Усі зображення, тексти та код, що розміщені на сайті, є інтелектуальною власністю власника сайту.</p>             <p>Неавторизоване використання чи відтворення цих матеріалів заборонено.</p>           <h2>Конфіденційність:</h2>            <p>Ми цінуємо вашу конфіденційність. Особиста інформація, яку ми збираємо, обробляється відповідно до нашої <a href="#">Політики конфіденційності</a>.</p>            <h2>Відмова від відповідальності:</h2>            <p>Власник сайту не несе відповідальності за результати гадань на картах Таро чи Рунах, наданих ШІ. Використання сайту та наданої інформації здійснюється на ваш ризик.</p>            <h2>Зміни в умовах:</h2>           <p>Власник сайту залишає за собою право оновлювати або змінювати ці Умови використання в будь-який час. Зміни набирають чинності відразу після публікації на сайті.</p>            <h2>Контакти:</h2>            <p>Якщо у вас є питання чи зауваження щодо цих Умов використання, будь ласка, зв'яжіться з нами за адресою: <a href="mailto:info@tell.guru">info@tell.guru</a>.</p>            <p>Використовуючи tell.guru, ви підтверджуєте, що ознайомилися з цими умовами і погоджуєтесь з ними. Дякуємо, що відвідали наш сайт!</p>`,Rules:`Правила`,Choice:`Роздоріжжя`,About:`Про проект`,"nav-help":`Знання`,"nav-path":`Шлях`,"nav-tarot":`Таро`,"nav-runes":`Руни`,"nav-faq":`FAQ`,"nav-login":`Вхід`,"nav-contact":`Зв'язатися зі мною`,"Contact Us":`Зв'яжіться з нами`,"Summon the Author":`Покликати автора`,"Contact Form":`Форма зв'язку`,"First Name":`Ім'я`,"Last Name":`Прізвище`,Email:`Email`,Subject:`Тема`,Message:`Повідомлення`,"Write your notes or questions here...":`Надішли знак автору крізь нитки долі...`,"Send Message":`Надіслати повідомлення`,"Sending...":`Надсилаємо...`,Sent:`Надіслано`,Error:`Помилка`,Password:`Пароль`,"Incorrect email or password":`Невірний email або пароль`,"Log out":`Вийти`,"Sign up":`Реєстрація`,"Create account":`Створити акаунт`,"Back to Login":`Назад до входу`,"nav-choose-path":`Стань на свій шлях`,"nav-tarot-sub":`Карти Долі`,"nav-tarot-hint":`78 арканів відкриють завісу таємниць`,"nav-runes-sub":`Знаки Прадавніх`,"nav-runes-hint":`Руни зберігають мудрість віків`,"nav-faq-sub":`Відповіді, приховані між рядками`,"nav-rules-sub":`Закони, що пов’язують невидиме`};function o(e){let t=`${e}=`,n=document.cookie.split(`;`);for(let e=0;e<n.length;e+=1){let r=n[e].trim();if(r.startsWith(t))return decodeURIComponent(r.slice(t.length))}return null}function s(e,t,n=365){let r=new Date;r.setTime(r.getTime()+n*24*60*60*1e3),document.cookie=`${e}=${encodeURIComponent(t)}; expires=${r.toUTCString()}; path=/; SameSite=Lax`}function c(e){document.cookie=`${e}=; Path=/; Expires=Thu, 01 Jan 1970 00:00:01 GMT; SameSite=Lax`}var l=`user_lang`,u={en:r,ru:i,ua:a};function d(){let e=o(l)||`en`;return u[e]?e:`en`}var f=n(`settings`,{state:()=>({lang:d()}),getters:{dictionary:e=>u[e.lang]||u.en},actions:{setLang(e){u[e]&&(this.lang=e,s(l,e))}}});function p(){let n=f(),{lang:r}=t(n),i=e(()=>n.dictionary);return{lang:r,t:e=>i.value[e]||e,setLang:e=>n.setLang(e)}}var m=`https://apps.baldcat.dev`,h=m.startsWith(`http`)?m:`https://${m}`,g=`/api/request.php`;function _(e){return h?new URL(e,h).toString():e}var v={tarotApi:_(`/tarot/api.php`),requestApi:g,adviceApi:`https://api.adviceslip.com/advice`};export{s as a,o as i,p as n,c as r,v as t};